SELECT COUNT(*)
FROM FWK_VALIDATION
WHERE VALIDATION_ID = #{validationId}

SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT
FROM FWK_VALIDATION v
ORDER BY
v.VALIDATION_ID v.VALIDATION_DESC v.FIELD_EVENT_TEXT v.MASK_TEXT v.CHAR_TYPE_TEXT v.JAVA_CLASS_NAME v.VALIDATION_ID
ASC DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
